module RefModule(
    Q  ,
    CLK,
    D  ,
    SCD,
    SCE
);output Q  ;
    input  CLK;
    input  D  ;
    input  SCD;
    input  SCE;


reg q_reg;
wire mux_out;
wire __SCE_tmp = (SCE == 1'b1);
assign mux_out = __SCE_tmp ? SCD : D;

always @ ( posedge CLK)
       begin
	     q_reg <= mux_out;
       end

assign Q = q_reg;

endmodule
